def normalize_legacy_schedule_triggers(apps, schema_editor):
    """
    Migrate old-style schedule triggers (hog-function-based with template_id/inputs/scheduled_at)
    to the new simple { "type": "schedule" } shape.

    ~37 rows across US/EU as of April 2026, all with past scheduled_at dates and effectively dormant.
    """
    HogFlow = apps.get_model("posthog", "HogFlow")
    for flow in HogFlow.objects.filter(trigger__type="schedule", trigger__has_key="template_id"):
        flow.trigger = {"type": "schedule"}
        flow.actions = [
            {**action, "config": {"type": "schedule"}}
            if action.get("type") == "trigger" and (action.get("config") or {}).get("type") == "schedule"
            else action
            for action in (flow.actions or [])
        ]
        flow.save(update_fields=["trigger", "actions"])


